transform.script:
const { documentIntent, contentDomain, reasoning } = result;
const taskText = triggeringMessage.content?.text || '';
if (!taskText || !taskText.trim()) throw new Error('ISSUE_OPENED has no text content — nothing to draft');

if (documentIntent === 'UNCERTAIN' || contentDomain === 'UNCERTAIN') {
  return {
    topic: 'CONDUCTOR_ESCALATE',
    content: {
      text: reasoning,
      data: { documentIntent, contentDomain, reasoning, taskText }
    }
  };
}

const getTier = () => {
  if (documentIntent === 'ACTIONABLE' && contentDomain === 'SENSITIVE') return 'prism';
  if (documentIntent === 'ACTIONABLE' || contentDomain === 'SENSITIVE') return 'lens';
  return 'facet';
};

const tier = getTier();
const tierParams = {
  facet: { drafter_level: 'level2', validator_count: 1, max_iterations: 3, max_tokens: 100000 },
  lens:  { drafter_level: 'level2', validator_count: 2, max_iterations: 4, max_tokens: 150000 },
  prism: { drafter_level: 'level3', validator_count: 3, max_iterations: 5, max_tokens: 150000 }
};

const has_action_items = documentIntent === 'ACTIONABLE';

const config = {
  base: 'doc-draft-workflow',
  params: {
    tier,
    ...tierParams[tier],
    has_action_items
  }
};

return {
  topic: 'CLUSTER_OPERATIONS',
  content: {
    text: `[DOC:${tier.toUpperCase()}] ${reasoning}`,
    data: {
      operations: [
        { action: 'load_config', config },
        { action: 'publish', topic: 'ISSUE_OPENED', content: { text: taskText }, metadata: { _republished: true } }
      ]
    }
  }
};

const { documentIntent, contentDomain, reasoning } = result;

const original = ledger.findLast({ topic: 'ISSUE_OPENED' });
let taskText = original?.content?.text || '';
if (!taskText || !taskText.trim()) throw new Error('Senior conductor could not recover task text — aborting to prevent drafting from empty brief');

const getTier = () => {
  if (documentIntent === 'ACTIONABLE' && contentDomain === 'SENSITIVE') return 'prism';
  if (documentIntent === 'ACTIONABLE' || contentDomain === 'SENSITIVE') return 'lens';
  return 'facet';
};

const tier = getTier();
const tierParams = {
  facet: { drafter_level: 'level2', validator_count: 1, max_iterations: 3, max_tokens: 100000 },
  lens:  { drafter_level: 'level2', validator_count: 2, max_iterations: 4, max_tokens: 150000 },
  prism: { drafter_level: 'level3', validator_count: 3, max_iterations: 5, max_tokens: 150000 }
};

const has_action_items = documentIntent === 'ACTIONABLE';

const config = {
  base: 'doc-draft-workflow',
  params: {
    tier,
    ...tierParams[tier],
    has_action_items
  }
};

return {
  topic: 'CLUSTER_OPERATIONS',
  content: {
    text: `Senior: [DOC:${tier.toUpperCase()}] ${reasoning}`,
    data: {
      operations: [
        { action: 'load_config', config },
        { action: 'publish', topic: 'ISSUE_OPENED', content: { text: taskText }, metadata: { _republished: true } }
      ]
    }
  }
};
